'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './status.module.css'

export interface StatusProps extends HTMLAttributes<HTMLSpanElement> {
  status?: 'success' | 'warning' | 'error' | 'info' | 'neutral'
  /** Pulses the dot — only when the user allows motion. */
  pulse?: boolean
}

export function Status({
  status = 'neutral',
  pulse = false,
  className,
  children,
  ...props
}: StatusProps) {
  return (
    <span
      data-status={status}
      data-pulse={pulse ? '' : undefined}
      className={cn(styles['status'], className as string | undefined)}
      {...props}
    >
      <span aria-hidden="true" className={styles['dot']} />
      {children}
    </span>
  )
}

@layer cascivo.component {
  .status {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-tight);

    &[data-status='success'] .dot {
      background-color: var(--cascivo-color-success);
    }

    &[data-status='warning'] .dot {
      background-color: var(--cascivo-color-warning);
    }

    &[data-status='error'] .dot {
      background-color: var(--cascivo-color-error);
    }

    &[data-status='info'] .dot {
      background-color: var(--cascivo-color-info);
    }

    &[data-status='neutral'] .dot {
      background-color: var(--cascivo-color-text-muted);
    }
  }

  .dot {
    inline-size: 0.5rem;
    block-size: 0.5rem;
    border-radius: var(--cascivo-radius-full);
    flex-shrink: 0;
  }

  @media (prefers-reduced-motion: no-preference) {
    .status[data-pulse] .dot {
      animation: cascade-status-pulse 2s var(--cascivo-ease-in-out) infinite;
    }
  }

  @keyframes cascade-status-pulse {
    0%,
    100% {
      opacity: 1;
    }

    50% {
      opacity: 0.4;
    }
  }
}
